// Componente de checkout
const CheckoutForm = ({ user, cart }) => {
  const calculateTotal = () => {
    let total = cart.items.reduce((sum, item) => sum + item.price, 0);

    // Lógica de negócio duplicada: desconto para usuários premium
    if (user.type === 'premium') {
      total = total * 0.9; // 10% desconto
    }

    // Lógica de negócio duplicada: frete grátis acima de R$ 100
    if (total < 100) {
      total += 15; // frete
    }

    return total;
  };

  return <div>Total: R$ {calculateTotal()}</div>;
};

