// services/pricing.ts - Lógica de negócio centralizada
export const calculateOrderTotal = (user: User, items: CartItem[]): number => {
  let total = items.reduce((sum, item) => sum + item.price, 0);

  // Regras de negócio em um lugar só
  if (user.type === 'premium') {
    total = total * 0.9; // 10% desconto para premium
  }

  if (total < 100) {
    total += 15; // frete grátis acima de R$ 100
  }

  return total;
};

// Componentes usam a lógica centralizada
const CheckoutForm = ({ user, cart }) => {
  const total = calculateOrderTotal(user, cart.items);
  return <div>Total: R$ {total}</div>;
};

const OrderSummary = ({ user, items }) => {
  const total = calculateOrderTotal(user, items);
  return <div>Total: R$ {total}</div>;
};

const CartWidget = ({ user, items }) => {
  const total = calculateOrderTotal(user, items);
  return <div>R$ {total}</div>;
};

